// src/dashboard/metrics.ts
import { Octokit } from '@octokit/rest';

const octokit = new Octokit({ auth: process.env.GITHUB_TOKEN });

async function fetchCopilotMetrics(org: string, since: string) {
  const response = await octokit.request('GET /orgs/{org}/copilot/metrics', {
    org,
    since,
    headers: { 'X-GitHub-Api-Version': '2022-11-28' },
  });
  return response.data.map(row => ({
    date: row.day,
    activUsers: row.total_active_users,
    suggestions: row.total_suggestions_count,
    linesAccepted: row.total_lines_accepted,
  }));
}
